plugin.generateCode:
const count = Math.max(1, Math.min(200, Number(options.count ?? 10)));
const interval = Math.max(1, Number(options.intervalSeconds ?? 60)) * 1000;
const fmt = options.format ?? 'iso';
const startRaw = (options.start ?? '').trim();
let startMs = startRaw ? new Date(startRaw).getTime() : Date.now();
if (isNaN(startMs)) startMs = Date.now();

const results = [];
for (let i = 0; i < count; i++) {
  const t = startMs + i * interval;
  const d = new Date(t);
  if (fmt === 'unix-ms') results.push(String(t));
  else if (fmt === 'unix-s') results.push(String(Math.floor(t / 1000)));
  else if (fmt === 'rfc2822') results.push(d.toUTCString());
  else if (fmt === 'date-only') results.push(d.toISOString().slice(0, 10));
  else if (fmt === 'time-only') results.push(d.toISOString().slice(11, 19) + 'Z');
  else results.push(d.toISOString());
}
return { output: results.join('\n'), outputLanguage: 'text' };
